exercises.solution:
function safeParseInt(value: string | null): number {
  if (value === null) {
    return 0;
  }
  const parsed = parseInt(value, 10);
  return isNaN(parsed) ? 0 : parsed;
}

console.log(safeParseInt("42"));
console.log(safeParseInt(null));
console.log(safeParseInt("abc"));

