exercises.solution:
function parseAge(value: string): number | null {
  const parsed = parseInt(value, 10);
  if (isNaN(parsed) || parsed <= 0) {
    return null;
  }
  return parsed;
}

console.log(parseAge("25"));
console.log(parseAge("-5"));
console.log(parseAge("abc"));
console.log(parseAge("0"));

