// Write the minMax function


console.log(minMax([3, 1, 4, 1, 5, 9, 2, 6]));
console.log(minMax([42]));

exercises.solution:
function minMax(nums: readonly number[]): [number, number] {
  let min = nums[0];
  let max = nums[0];
  for (const n of nums) {
    if (n < min) min = n;
    if (n > max) max = n;
  }
  return [min, max];
}

console.log(minMax([3, 1, 4, 1, 5, 9, 2, 6]));
console.log(minMax([42]));
